import{_ as l,o as a,c as e,a2 as s}from"./chunks/framework.CW5cCyjm.js";const k=JSON.parse('{"title":"交付契约与设计说明规则","description":"","frontmatter":{},"headers":[],"relativePath":"mango-pmo/rules/01-delivery-contract.md","filePath":"mango-pmo/rules/01-delivery-contract.md"}'),t={name:"mango-pmo/rules/01-delivery-contract.md"};function o(d,i,n,c,r,h){return a(),e("div",null,[...i[0]||(i[0]=[s(`<h1 id="交付契约与设计说明规则" tabindex="-1">交付契约与设计说明规则 <a class="header-anchor" href="#交付契约与设计说明规则" aria-label="Permalink to &quot;交付契约与设计说明规则&quot;">​</a></h1><h2 id="_1-适用范围" tabindex="-1">1. 适用范围 <a class="header-anchor" href="#_1-适用范围" aria-label="Permalink to &quot;1. 适用范围&quot;">​</a></h2><p>适用于需要完整交付确认的正式任务，包括需求、设计、开发、测试、验收、发布、PR、按设计文档推进、按 Sprint 推进和按交付台账推进。</p><p>以下任务不强制建立交付契约和交付台账：</p><ul><li>简单查询、状态确认、日志查看、切换目录、关闭进程。</li><li>只读定位文件、类、接口、配置、worktree 或报错片段。</li><li>只修改规范、流程、设计文档、交付记录、Agent 入口或 PMO 临时复盘，且不影响服务代码、接口、数据库、测试、前端页面或构建配置。</li></ul><p>豁免任务仍必须说明目标、改动范围、验证方式和风险。</p><h2 id="_2-目标" tabindex="-1">2. 目标 <a class="header-anchor" href="#_2-目标" aria-label="Permalink to &quot;2. 目标&quot;">​</a></h2><p>防止 Agent 将任务压缩成极简主链路、聚合页、演示页、临时实现或不可用交付。</p><h2 id="_3-开工门禁" tabindex="-1">3. 开工门禁 <a class="header-anchor" href="#_3-开工门禁" aria-label="Permalink to &quot;3. 开工门禁&quot;">​</a></h2><p>开始正式需求、设计、编码、测试、验收、发布或 PR 前，必须先明确交付契约。</p><p>交付契约必须说明：</p><ul><li>目标</li><li>范围</li><li>不做什么</li><li>设计输入</li><li>交付物</li><li>验收方式</li><li>测试用例登记与自动化判断</li><li>E2E 覆盖判断</li><li>测试结果基线</li><li>业务开发交接输出</li><li>风险与限制</li></ul><h2 id="_4-设计说明门禁" tabindex="-1">4. 设计说明门禁 <a class="header-anchor" href="#_4-设计说明门禁" aria-label="Permalink to &quot;4. 设计说明门禁&quot;">​</a></h2><p>实质任务必须有明确设计说明。</p><ul><li>已有设计文档时，设计说明必须引用该文档并抽取原子要求。</li><li>没有设计文档时，必须先为本次任务产出轻量设计说明。</li><li>设计说明必须写清模块边界、接口变化、数据变化、菜单/页面/权限变化、测试范围。</li><li>对外能力新增、修改、删除或重构时，设计说明必须写清 README、需求文档、设计文档、E2E 脚本和测试结果基线是否需要同步更新。</li><li>未经用户确认，禁止把完整任务改成 MVP、第一阶段、纵向切片或演示版本。</li></ul><h2 id="_5-交付台账门禁" tabindex="-1">5. 交付台账门禁 <a class="header-anchor" href="#_5-交付台账门禁" aria-label="Permalink to &quot;5. 交付台账门禁&quot;">​</a></h2><p>开始编码或交付前，必须建立交付台账。</p><p>交付契约必须按 <a href="https://github.com/HardyDou/mango/blob/main/mango-pmo/rules/09-test-case-automation-flow.md" target="_blank" rel="noreferrer">测试用例与自动化工程化流程</a> 登记测试用例候选项，明确每个验收项的测试层级、优先级、自动化判断、测试数据、稳定契约、执行入口、证据和状态。</p><p>交付台账必须从用户要求、设计说明、设计文档和验收标准中抽取原子验收项，逐项记录：</p><ul><li><code>ID</code></li><li><code>来源</code></li><li><code>要求</code></li><li><code>设计决策</code></li><li><code>代码交付物</code></li><li><code>README/使用说明</code></li><li><code>需求/设计文档</code></li><li><code>E2E 脚本</code></li><li><code>测试结果基线</code></li><li><code>验收方式</code></li><li><code>状态</code></li><li><code>证据文件</code></li></ul><p>推荐使用模板：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>mango-pmo/templates/delivery-contract.md</span></span></code></pre></div><h2 id="_6-原子验收项规则" tabindex="-1">6. 原子验收项规则 <a class="header-anchor" href="#_6-原子验收项规则" aria-label="Permalink to &quot;6. 原子验收项规则&quot;">​</a></h2><ul><li>一个后台能力、业务能力、接口能力、数据能力、菜单能力、页面能力、权限能力或验收标准必须是一条独立台账项。</li><li>多个能力禁止合并成一个“管理页”“概览页”“主流程”“通用能力”台账项。</li><li>要求涉及菜单、页面、API、数据、权限、E2E 时，台账项必须逐类列出代码交付物、README 或使用说明、需求或设计文档、E2E 脚本、测试结果基线和验收证据。</li><li>新增、修改、删除或重构对外能力时，台账项必须关联 E2E 覆盖判断；不需要 E2E 脚本或结果基线时，对应物料单元格必须按 <code>EXCEPTION: &lt;原因/确认依据&gt;</code> 写明用户确认依据或不适用原因。</li><li>无法落地的项必须标记为 <code>EXCEPTION</code>，并记录用户确认依据。</li></ul><h2 id="_7-禁止替代" tabindex="-1">7. 禁止替代 <a class="header-anchor" href="#_7-禁止替代" aria-label="Permalink to &quot;7. 禁止替代&quot;">​</a></h2><p>未经用户明确确认，禁止用以下内容替代交付契约：</p><ul><li>用聚合页替代多个独立管理页面。</li><li>用 MVP、第一阶段、纵向切片替代完整范围。</li><li>用主链路跑通替代完整后台、接口、数据和验收能力。</li><li>用前端临时菜单替代后端入库菜单。</li><li>用 Mock、虚拟、演示数据替代要求的沙箱或真实能力。</li><li>用单元测试、接口 200、页面打开或口头说明替代应有的 E2E 脚本和测试结果基线。</li><li>用“后续优化”“未来补齐”替代本次明确要求。</li></ul><h2 id="_8-验证门禁" tabindex="-1">8. 验证门禁 <a class="header-anchor" href="#_8-验证门禁" aria-label="Permalink to &quot;8. 验证门禁&quot;">​</a></h2><p>交付前必须执行：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">node</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> mango-pmo/tools/delivery-contract-check.mjs</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --design</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">设计说明或设计文档路</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">径</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --ledger</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">交付台账路</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">径</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --mode</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> verify</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --require-materials</span></span></code></pre></div><p>验证模式下：</p><ul><li>设计说明或设计文档必须存在。</li><li>台账必须存在。</li><li>必填列必须完整。</li><li>必需交付项必须存在。</li><li><code>--require-materials</code> 开启时，代码交付物、README/使用说明、需求/设计文档、E2E 脚本、测试结果基线、验收方式和证据文件必须逐项填写；不适用时必须在对应物料单元格按 <code>EXCEPTION: &lt;原因/确认依据&gt;</code> 写明。</li><li><code>--require-materials</code> 开启时，必须填写业务开发交接输出；不适用时必须按 <code>EXCEPTION: &lt;原因/确认依据&gt;</code> 写明。</li><li>状态必须为 <code>DONE</code> 或 <code>EXCEPTION</code>。</li><li><code>EXCEPTION</code> 必须有证据文件或用户确认说明。</li><li>交付范围内不得存在 <code>TODO</code>、<code>FIXME</code>、<code>mock</code>、<code>virtual</code>、<code>模拟</code>、<code>伪代码</code>、<code>未来优化</code>、<code>后续优化</code> 等未交付标记。</li></ul><h2 id="_9-交付报告" tabindex="-1">9. 交付报告 <a class="header-anchor" href="#_9-交付报告" aria-label="Permalink to &quot;9. 交付报告&quot;">​</a></h2><p>最终交付必须报告：</p><ul><li>交付台账路径。</li><li>台账总项数。</li><li><code>DONE</code> 项数。</li><li><code>EXCEPTION</code> 项数。</li><li>E2E 脚本路径或 EXCEPTION 依据。</li><li>测试结果基线路径或 EXCEPTION 依据。</li><li>未完成项。</li><li>台账检查命令与结果。</li><li>新增、修改、废弃的测试用例清单。</li><li>面向业务开发者的测试用例、执行入口、数据边界、失败处理和升级动作。</li></ul><p>未完成项不为 0 时，禁止声明“完成”。</p>`,36)])])}const E=l(t,[["render",o]]);export{k as __pageData,E as default};
